function readBinaryWatch(turnedOn) {
    function countBits(n) {
        return n.toString(2).split('1').length - 1;
    }

    const times = [];
    for (let h = 0; h < 12; h++) {
        for (let m = 0; m < 60; m++) {
            if (countBits(h) + countBits(m) === turnedOn) {
                times.push(`${h}:${m.toString().padStart(2, '0')}`);
            }
        }
    }
    return times;
}
